- package hat.dialect;
-
- import jdk.incubator.code.CodeContext;
- import jdk.incubator.code.CodeTransformer;
- import jdk.incubator.code.Op;
- import jdk.incubator.code.TypeElement;
- import jdk.incubator.code.Value;
- import jdk.incubator.code.dialect.java.JavaOp;
- import optkl.util.ops.Precedence;
-
- import java.util.List;
- import java.util.Map;
-
- public final class HATMathLibOp extends HATOp implements Precedence.Invoke {
-
-     private final TypeElement typeElement;
-     private final String name;
-
-     public HATMathLibOp(TypeElement typeElement, String name, List<Value> operands) {
-         super(operands);
-         this.typeElement = typeElement;
-         this.name = name;
-     }
-
-     public HATMathLibOp(HATMathLibOp hatMathBinaryOp, CodeContext codeContext) {
-         super(hatMathBinaryOp, codeContext);
-         this.typeElement = hatMathBinaryOp.typeElement;
-         this.name = hatMathBinaryOp.name;
-     }
-
-     @Override
-     public Op transform(CodeContext codeContext, CodeTransformer codeTransformer) {
-         return new HATMathLibOp(this, codeContext);
-     }
-
-     @Override
-     public TypeElement resultType() {
-         return typeElement;
-     }
-
-     @Override
-     public Map<String, Object> externalize() {
-         return Map.of("hat.dialect.MathLib." + name, JavaOp.InvokeOp.InvokeKind.INSTANCE);
-     }
-
-     public String name() {
-         return name;
-     }
- }
